package com.comp2154.student_system.controller;
import com.comp2154.student_system.dto.*; import com.comp2154.student_system.service.GradeService; import jakarta.validation.Valid; import java.util.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/grades")
public class GradeController { private final GradeService service; public GradeController(GradeService service){this.service=service;} @GetMapping public List<GradeView> getAllGrades(){return service.getAllGrades();} @GetMapping("/student/{studentId}") public List<GradeView> getGradesForStudent(@PathVariable Integer studentId){return service.getGradesForStudent(studentId);} @PostMapping public ResponseEntity<GradeView> createGrade(@Valid @RequestBody GradeRequest req){ return ResponseEntity.status(HttpStatus.CREATED).body(service.createGrade(req)); } @PutMapping("/{id}") public GradeView updateGrade(@PathVariable Long id,@Valid @RequestBody GradeRequest req){ return service.updateGrade(id,req);} @DeleteMapping("/{id}") public Map<String,String> deleteGrade(@PathVariable Long id){ service.deleteGrade(id); return Map.of("message","Grade deleted successfully"); } }
